import Link from '@kyokuya/react-link'
import loadable from '@loadable/component'
import type {
  Definition,
  EcmaImport,
  FootnoteDefinition,
  YastNode,
} from '@yozora/ast'
import type { CodeRunnerScope } from '@yozora/react-code'
import YozoraMarkdown, {
  createYozoraNodesRenderer,
} from '@yozora/react-markdown'
import type {
  PreviewImageApi,
  TokenRendererMap,
  MarkdownProps as YozoraMarkdownProps,
} from '@yozora/react-markdown'
import React from 'react'
import { customRendererMap, useCodeRunners } from './renderer'

export * from './renderer'

const Viewer = loadable(() => import('react-viewer'))

const footnoteDefinitionsTitle: React.ReactNode = (
  <Link url="#footnote-definitions">
    <span id="footnote-definitions">footnote-definitions</span>
  </Link>
)

export interface MarkdownProps extends YozoraMarkdownProps {
  ecmaImports: EcmaImport[]
  jsxScope?: CodeRunnerScope
}

export function Markdown(props: MarkdownProps): React.ReactElement {
  const { ecmaImports, jsxScope } = props
  const codeRunners = useCodeRunners(ecmaImports, jsxScope)
  return (
    <YozoraMarkdown
      rendererMap={customRendererMap}
      codeRunners={codeRunners}
      footnoteDefinitionsTitle={footnoteDefinitionsTitle}
      {...props}
      Viewer={Viewer}
    />
  )
}

export function createMarkdownNodesRenderer(
  rendererMap: TokenRendererMap,
  definitionMap: Record<string, Definition>,
  footnoteDefinitionMap: Record<string, FootnoteDefinition>,
  imageContext?: PreviewImageApi,
): (nodes: YastNode[]) => React.ReactNode[] {
  return createYozoraNodesRenderer(
    rendererMap,
    definitionMap,
    footnoteDefinitionMap,
    imageContext,
  )
}

export default Markdown
