import { ReactAPlayer } from '@kyokuya/react-aplayer'
import Link from '@kyokuya/react-link'
import ReactMarkdown from '@kyokuya/react-markdown'
import {
  NavigateBeforeOutlined,
  NavigateNextOutlined,
} from '@material-ui/icons'
import type {
  Definition,
  EcmaImport,
  FootnoteDefinition,
  Root,
} from '@yozora/ast'
import type { APlayerOptions } from 'aplayer'
import cn from 'clsx'
import React, { useContext, useMemo } from 'react'
import BlogContext from '../context'
import classes from '../style/index.module.styl'

export interface PostContentProps {
  title: string
  createAt: string
  timeToRead: string
  tags: string[]
  ast: Root
  ecmaImports: EcmaImport[]
  definitionMap: Record<string, Definition>
  footnoteDefinitionMap: Record<string, FootnoteDefinition>
  slug: string
  aplayer?: APlayerOptions
  previous?: {
    title: string
    fields: {
      slug: string
    }
  }
  next?: {
    title: string
    fields: {
      slug: string
    }
  }
  /**
   * Whether to render the footer
   * @default true
   */
  shouldRenderFooter?: boolean
}

/**
 * Render contents of a ReactMarkdown post.
 */
export function PostContent(props: PostContentProps): React.ReactElement {
  const {
    title,
    createAt,
    timeToRead,
    tags,
    ast,
    ecmaImports,
    definitionMap,
    footnoteDefinitionMap,
    slug,
    aplayer,
    previous,
    next,
    shouldRenderFooter = true,
  } = props

  const { setKeyword, setMagicPanelVisible, setMagicPanelActivated } =
    useContext(BlogContext)
  const result = useMemo<React.ReactElement>(
    () => (
      <section
        className={cn(
          classes.postCard,
          classes.frostedGlassPanel,
          classes.postCard,
        )}
      >
        <header className={classes.postCardHeader}>
          <h1>
            <Link title={title} url={slug} itemProp="url">
              <span itemProp="headline">{title}</span>
            </Link>
          </h1>
          <div className={classes.postCardHeaderMeta}>
            <div>
              <span
                key="createAt"
                className={classes.postCardHeaderDate}
                itemProp="datePublished"
              >
                {createAt} • &nbsp;🍻&nbsp;{timeToRead} read
              </span>
            </div>
            <div>
              {tags.length > 0 && (
                <React.Fragment>
                  🔖&nbsp;
                  {tags.map(tag => (
                    <span
                      key={tag}
                      className={classes.postCardHeaderTag}
                      onClick={e => {
                        e.stopPropagation()
                        setKeyword('#' + tag)
                        setMagicPanelVisible(true)
                        setMagicPanelActivated('search')
                      }}
                    >
                      {tag}
                    </span>
                  ))}
                </React.Fragment>
              )}
            </div>
          </div>
        </header>
        {aplayer != null && (
          <ReactAPlayer className={classes.postCardAplayer} options={aplayer} />
        )}
        <div className="clearfix" />
        <article className={classes.postCardMain}>
          <ReactMarkdown
            ast={ast}
            ecmaImports={ecmaImports}
            definitionMap={definitionMap}
            footnoteDefinitionMap={footnoteDefinitionMap}
          />
        </article>
        {shouldRenderFooter && (
          <footer className={classes.postCardFooter}>
            {previous != null && (
              <div className={classes.postCardFooterPrevious}>
                <Link url={previous.fields.slug}>
                  <NavigateBeforeOutlined />
                  <span>{previous.title}</span>
                </Link>
              </div>
            )}
            {next != null && (
              <div className={classes.postCardFooterNext}>
                <Link url={next.fields.slug}>
                  <span>{next.title}</span>
                  <NavigateNextOutlined />
                </Link>
              </div>
            )}
          </footer>
        )}
      </section>
    ),
    [
      title,
      createAt,
      timeToRead,
      tags,
      ast,
      definitionMap,
      footnoteDefinitionMap,
      slug,
      previous,
      next,
      shouldRenderFooter,
      setKeyword,
      setMagicPanelVisible,
      setMagicPanelActivated,
    ],
  )
  return result
}

PostContent.displayName = 'BlogPostContent'
export default PostContent
