import Link from '@kyokuya/react-link'
import { IconButton, Input, Switch, withStyles } from '@material-ui/core'
import CancelIcon from '@material-ui/icons/ClearOutlined'
import SearchIcon from '@material-ui/icons/SearchOutlined'
import cn from 'clsx'
import Fuse from 'fuse.js'
import React, { useContext, useMemo, useState } from 'react'
import BlogContext from '../context'
import classes from '../style/index.module.styl'

export interface PostItem {
  title: string
  createAt: string
  tags: string[]
  fields: {
    slug: string
  }
}

export interface BlogLayoutSearchPanelProps {
  items: PostItem[]
  className?: string
}

const TagListSwitch = withStyles({
  switchBase: {
    color: '#f6e1cc',
    '&$checked': {
      color: '#eda090',
    },
    '&$checked + $track': {
      backgroundColor: '#eda090',
    },
  },
  checked: {},
  track: {},
})(Switch)

export function BlogLayoutSearchPanel(
  props: BlogLayoutSearchPanelProps,
): React.ReactElement {
  const { items: nodes } = props
  const [tagListVisible, setTagListVisible] = useState<boolean>(false)
  const { tags, fullItems, titleSearcher, tagSearcher } = useMemo(() => {
    const tagSet: Set<string> = new Set()
    for (const node of nodes) {
      for (const tag of node.tags) tagSet.add(tag)
    }
    const tags: string[] = Array.from(tagSet).sort()

    const items = nodes.map(node => ({
      title: node.title,
      createAt: node.createAt,
      tags: node.tags,
      fields: {
        slug: node.fields.slug,
      },
    }))

    const fullItems: Array<Fuse.FuseResult<PostItem>> = items.map(
      (item, index) => ({
        item,
        matches: [],
        score: 1,
        refIndex: index,
      }),
    )
    const titleSearcher = new Fuse<PostItem>(items, {
      includeScore: true,
      findAllMatches: true,
      keys: ['title'],
    })
    const tagSearcher = new Fuse<PostItem>(items, {
      includeScore: true,
      threshold: 0.4,
      keys: ['tags'],
    })
    return { tags, fullItems, titleSearcher, tagSearcher }
  }, [nodes])

  const { keyword, setKeyword } = useContext(BlogContext)
  const resolvedKeyword = keyword.trim()
  const resolvedItems =
    resolvedKeyword.length <= 0
      ? fullItems
      : resolvedKeyword[0] === '#'
      ? tagSearcher.search(resolvedKeyword)
      : titleSearcher.search(resolvedKeyword)

  return (
    <div className={cn(classes.searchPanel, props.className)}>
      <Input
        className={classes.searchPanelInput}
        type="input"
        value={keyword}
        placeholder="Searching post..."
        autoFocus={true}
        onChange={e => setKeyword(e.target.value)}
        endAdornment={
          <React.Fragment>
            <SearchIcon className={cn({ hidden: keyword.length > 0 })} />
            <IconButton
              className={cn({ hidden: keyword.length <= 0 })}
              onClick={() => setKeyword('')}
            >
              <CancelIcon />
            </IconButton>
          </React.Fragment>
        }
      />
      <div className={classes.searchPanelResult}>
        <div className={classes.searchPanelTagListSwitchWrapper}>
          <span onClick={() => setTagListVisible(v => !v)}>tags</span>
          <TagListSwitch
            checked={tagListVisible}
            onChange={() => setTagListVisible(v => !v)}
          />
        </div>
        <div
          className={cn(classes.searchPanelTagList, {
            hidden: !tagListVisible,
          })}
        >
          {tags.map(tag => (
            <span
              key={tag}
              className={classes.searchPanelTagItem}
              onClick={e => {
                e.stopPropagation()
                setKeyword('#' + tag)
              }}
            >
              {tag}
            </span>
          ))}
        </div>
        <ul className={classes.searchPanelResultList}>
          {resolvedItems.map(({ item }) => (
            <li key={item.title} className={classes.searchPanelResultItem}>
              <Link
                className={classes.searchPanelResultItemHeader}
                url={item.fields.slug}
                itemProp="url"
              >
                {item.title}
              </Link>
              <div className={classes.searchPanelResultItemBody}>
                <span
                  key="__date"
                  className={classes.searchPanelResultItemDate}
                >
                  {item.createAt}
                </span>
                🔖&nbsp;
                {item.tags.map(tag => (
                  <span
                    key={tag}
                    className={classes.searchPanelResultItemTag}
                    onClick={() => setKeyword('#' + tag)}
                  >
                    #{tag}
                  </span>
                ))}
              </div>
            </li>
          ))}
        </ul>
      </div>
    </div>
  )
}

BlogLayoutSearchPanel.displayName = 'BlogLayoutSearchPanel'
export default BlogLayoutSearchPanel
